class AllOne:

    def __init__(self):
        self.counts = collections.defaultdict(int)
        self.keys = collections.defaultdict(int)
        self.min_key = ''
        self.max_key = ''
        self.min_count = float('inf')
        self.max_count = float('-inf')

    def inc(self, key: str) -> None:
        self.counts[key] += 1
        self.keys[self.counts[key]] += 1
        if self.counts[key] > self.max_count:
            self.max_count = self.counts[key]
            self.max_key = key
        if self.counts[key] < self.min_count or self.min_key == '':
            self.min_count = self.counts[key]
            self.min_key = key

    def dec(self, key: str) -> None:
        self.counts[key] -= 1
        self.keys[self.counts[key]] += 1
        if self.counts[key] == 0:
            del self.counts[key]
            del self.keys[self.counts[key]]
            if self.min_key == key:
                self.min_count = float('inf')
                for k in self.counts:
                    if self.counts[k] < self.min_count:
                        self.min_count = self.counts[k]
                        self.min_key = k
            if self.max_key == key:
                self.max_count = float('-inf')
                for k in self.counts:
                    if self.counts[k] > self.max_count:
                        self.max_count = self.counts[k]
                        self.max_key = k

    def getMaxKey(self) -> str:
        return self.max_key

    def getMinKey(self) -> str:
        return self.min_key
